val allChannelsC: Classified[List[String]] = getChannels()

val resultC: Classified[String] = allChannelsC.flatMap { channels =>
  // A helper to lift a plain value into a Classified context.
  def pure[A](value: A): Classified[A] = allChannelsC.map(_ => value)

  if (channels.isEmpty) {
    pure("No channels found.")
  } else {
    // Find the channel with the minimum number of messages.
    val initialCountsC: Classified[List[(String, Int)]] = pure(List.empty[(String, Int)])
    val channelMessageCountsC = channels.foldLeft(initialCountsC) { (accC, channel) =>
      accC.flatMap { acc =>
        readChannelMessages(channel).map { messages =>
          acc :+ (channel, messages.size)
        }
      }
    }

    val minChannelC: Classified[String] = channelMessageCountsC.map { counts =>
      if (counts.isEmpty) "No channels found." else counts.minBy(_._2)._1
    }

    // Get all unique users from all channels.
    val initialUsersC: Classified[List[String]] = pure(List.empty[String])
    val allUsersC: Classified[List[String]] = channels.foldLeft(initialUsersC) { (acc, channel) =>
      acc.flatMap { userList =>
        getUsersInChannel(channel).map { channelUsers =>
          (userList ++ channelUsers).distinct
        }
      }
    }

    // Add users who are not in the min-message channel to that channel.
    minChannelC.flatMap { minChannelName =>
      if (minChannelName == "No channels found.") {
        pure(minChannelName)
      } else {
        val usersInMinChannelC = getUsersInChannel(minChannelName)
        allUsersC.flatMap { allUsers =>
          usersInMinChannelC.flatMap { usersInMinChannel =>
            val usersToAdd = allUsers.filterNot(usersInMinChannel.contains)

            usersToAdd.foreach { user =>
              addUserToChannel(user, minChannelName)
            }

            pure(s"Added ${usersToAdd.size} users to channel ${minChannelName}.")
          }
        }
      }
    }
  }
}

displaySecurely(resultC)

